1	import {
2	  App,
3	  Editor,
4	  MarkdownFileInfo,
5	  MarkdownView,
6	  Notice,
7	  Plugin,
8	  PluginSettingTab,
9	  Setting,
10	  TFile,
11	} from 'obsidian';
12	import type { OutlineDoc, OutlineNode } from '../model';
13	import { parse } from '../parse';
14	import { indent, moveDown, moveUp, outdent } from '../ops';
15	import type { OpOutput } from '../ops';
16	import type { OpResult } from '../result';
17	import { OutlineModeRegistry, DEFAULT_DATA, type PluginData } from './mode-registry';
18	import { nodeAtLine } from './locate';
19	import { editsToChanges } from './dispatch';
20	import { REJECTION_MESSAGES } from './messages';
21	import { compareWithSections, type SectionInfo } from './crosscheck';
22	import { grammarExtension } from './keymap';
23	import { decorationsExtension, type MarkerVisibility } from './decorations';
24	
25	const MARKER_VISIBILITY_LABELS: Record<MarkerVisibility, string> = {
26	  all: 'All eligible kinds (status quo)',
27	  'with-children': 'Only nodes that have children',
28	  'headings-and-paragraphs': 'Only headings and paragraphs',
29	};
30	
31	type StructuralOp = (doc: OutlineDoc, nodeId: number) => OpResult<OpOutput>;
32	
33	const CONFLICTING_PLUGINS = ['obsidian-outliner', 'obsidian-zoom'];
34	
35	export default class TrueOutlinerPlugin extends Plugin {
36	  private data: PluginData = { ...DEFAULT_DATA };
37	  private registry!: OutlineModeRegistry;
38	
39	  override async onload(): Promise<void> {
40	    this.data = { ...DEFAULT_DATA, ...((await this.loadData()) as Partial<PluginData> | null) };
41	    this.registry = new OutlineModeRegistry(async (paths) => {
42	      this.data.outlinePaths = paths;
43	      await this.saveData(this.data);
44	    });
45	    this.registry.hydrate(this.data.outlinePaths);
46	
47	    this.addCommand({
48	      id: 'toggle-outline-mode',
49	      name: 'Toggle outline mode',
50	      editorCheckCallback: (checking, _editor, ctx) => {
51	        const path = ctx.file?.path;
52	        if (!path) return false;
53	        if (!checking) void this.toggleMode(path);
54	        return true;
55	      },
56	    });
57	
58	    this.addStructuralCommand('indent-node', 'Indent node', indent);
59	    this.addStructuralCommand('outdent-node', 'Outdent node', outdent);
60	    this.addStructuralCommand('move-node-up', 'Move node up', moveUp);
61	    this.addStructuralCommand('move-node-down', 'Move node down', moveDown);
62	
63	    this.registerEvent(
64	      this.app.vault.on('rename', (file, oldPath) => {
65	        if (file instanceof TFile) void this.registry.handleRename(oldPath, file.path);
66	      }),
67	    );
68	    this.registerEvent(
69	      this.app.vault.on('delete', (file) => {
70	        if (file instanceof TFile) void this.registry.handleDelete(file.path);
71	      }),
72	    );
73	    this.registerEvent(
74	      this.app.workspace.on('editor-menu', (menu, _editor, info) => {
75	        const path = info.file?.path;
76	        if (!path || !path.endsWith('.md')) return;
77	        const on = this.registry.isOutline(path);
78	        menu.addItem((item) =>
79	          item
80	            .setTitle(on ? 'Disable outline mode' : 'Enable outline mode')
81	            .setIcon('list-tree')
82	            .onClick(() => void this.toggleMode(path)),
83	        );
84	      }),
85	    );
86	
87	    this.registerEditorExtension(grammarExtension(this));
88	    this.registerEditorExtension(decorationsExtension(this));
89	
90	    this.addSettingTab(new TrueOutlinerSettingTab(this.app, this));
91	
92	    this.app.workspace.onLayoutReady(() => void this.warnAboutConflicts());
93	  }
94	
95	  isOutline(path: string): boolean {
96	    return this.registry.isOutline(path);
97	  }
98	
99	  get debugCrossCheck(): boolean {
100	    return this.data.debugCrossCheck;
101	  }
102	
103	  async setDebugCrossCheck(value: boolean): Promise<void> {
104	    this.data.debugCrossCheck = value;
105	    await this.saveData(this.data);
106	  }
107	
108	  get markerVisibility(): MarkerVisibility {
109	    return this.data.markerVisibility;
110	  }
111	
112	  async setMarkerVisibility(value: MarkerVisibility): Promise<void> {
113	    this.data.markerVisibility = value;
114	    await this.saveData(this.data);
115	    await this.forceRedraw();
116	  }
117	
118	  /**
119	   * A plain cursor nudge (what `refreshDecorations` uses for the mode
120	   * toggle) forces `computeDecorations`/`computeMarkers` to recompute, but
121	   * doesn't reliably reach `MarginCompensation` — a ViewPlugin with no
122	   * decorations of its own, whose `docViewUpdate` hook only fires when
123	   * SOME decoration source's output actually differs (CM6's own doc
124	   * comment: "due to content, decoration, or viewport changes"). For a
125	   * note containing only widget-replaced atoms (table/callout/hr/html —
126	   * `computeMarkers` deliberately skips these; `computeDecorations` doesn't
127	   * read `markerVisibility` at all), changing the setting produces
128	   * byte-identical StateField output, so CM6 correctly sees no diff and
129	   * never re-fires `docViewUpdate` — confirmed live: a table-only note's
130	   * marker visibility silently failed to update until this fix.
131	   *
132	   * Toggling outline mode off then immediately back on (via the registry
133	   * directly, not `toggleMode` — no user-facing Notice for an internal
134	   * refresh) guarantees two GENUINELY different decoration outputs
135	   * (`Decoration.none` vs. the real thing) regardless of note content,
136	   * which CM6 always detects as a real change — reliably triggering
137	   * `docViewUpdate` twice, with the second pass reading the just-saved
138	   * setting. Both toggles are public-API-only (an `Editor.setCursor` per
139	   * step, same trick `refreshDecorations` already uses) — no private CM6
140	   * access, consistent with this project's own public-API-only bar.
141	   */
142	  private async forceRedraw(): Promise<void> {
143	    const view = this.app.workspace.getActiveViewOfType(MarkdownView);
144	    const path = view?.file?.path;
145	    if (!view || !path || !this.registry.isOutline(path)) return; // nothing rendered to refresh
146	    await this.registry.toggle(path); // off
147	    view.editor.setCursor(view.editor.getCursor());
148	    await this.registry.toggle(path); // back on, now reading the new setting
149	    view.editor.setCursor(view.editor.getCursor());
150	  }
151	
152	  private async toggleMode(path: string): Promise<void> {
153	    const on = await this.registry.toggle(path);
154	    new Notice(on ? 'Outline mode on' : 'Outline mode off', 1500);
155	    this.refreshDecorations(path);
156	  }
157	
158	  /**
159	   * Toggling outline mode doesn't itself dispatch a CM6 transaction, so
160	   * decorationsExtension's StateField never gets a chance to recompute.
161	   * Nudging the cursor to its own position is a real (public-API) dispatch
162	   * that forces the recompute without changing anything visible.
163	   */
164	  private refreshDecorations(path: string): void {
165	    const view = this.app.workspace.getActiveViewOfType(MarkdownView);
166	    if (view?.file?.path !== path) return;
167	    view.editor.setCursor(view.editor.getCursor());
168	  }
169	
170	  private addStructuralCommand(id: string, name: string, op: StructuralOp): void {
171	    this.addCommand({
172	      id,
173	      name,
174	      editorCheckCallback: (checking, editor, ctx) => {
175	        const path = ctx.file?.path;
176	        if (!path || !this.registry.isOutline(path)) return false;
177	        if (!checking) this.runOp(editor, ctx, op);
178	        return true;
179	      },
180	    });
181	  }
182	
183	  private runOp(editor: Editor, ctx: MarkdownView | MarkdownFileInfo, op: StructuralOp): void {
184	    // Fresh-tree guarantee: always parse the current buffer at invocation.
185	    const text = editor.getValue();
186	    const doc = parse(text);
187	    if (this.data.debugCrossCheck && ctx.file) this.crossCheck(doc, ctx.file);
188	
189	    const node: OutlineNode | undefined = nodeAtLine(doc, editor.getCursor().line);
190	    if (!node) {
191	      new Notice(REJECTION_MESSAGES['node-not-found'], 1500);
192	      return;
193	    }
194	    const result = op(doc, node.id);
195	    if (!result.ok) {
196	      new Notice(REJECTION_MESSAGES[result.rejection.reason], 1500);
197	      return;
198	    }
199	    const lines = text === '' ? [] : text.split('\n');
200	    const changes = editsToChanges(lines, result.value.edits);
201	    if (changes.length > 0) editor.transaction({ changes });
202	    editor.setCursor(result.value.cursor);
203	  }
204	
205	  private crossCheck(doc: OutlineDoc, file: TFile): void {
206	    const sections = this.app.metadataCache.getFileCache(file)?.sections;
207	    if (!sections) return;
208	    const mapped: SectionInfo[] = sections.map((section) => ({
209	      type: section.type,
210	      startLine: section.position.start.line,
211	      endLine: section.position.end.line,
212	    }));
213	    const issues = compareWithSections(doc, mapped);
214	    if (issues.length > 0) {
215	      console.warn(
216	        `[true-outliner] parse disagreement in ${file.path} — candidate corpus fixture:`,
217	        issues,
218	      );
219	    }
220	  }
221	
222	  private async warnAboutConflicts(): Promise<void> {
223	    if (this.data.coexistenceWarned) return;
224	    const configPath = `${this.app.vault.configDir}/community-plugins.json`;
225	    let enabled: string[] = [];
226	    try {
227	      enabled = JSON.parse(await this.app.vault.adapter.read(configPath)) as string[];
228	    } catch {
229	      return; // no community plugins file — nothing to warn about
230	    }
231	    const conflicts = CONFLICTING_PLUGINS.filter((id) => enabled.includes(id));
232	    if (conflicts.length === 0) return;
233	    new Notice(
234	      `True Outliner: ${conflicts.join(' and ')} ${conflicts.length > 1 ? 'are' : 'is'} enabled — ` +
235	        'overlapping outliner behavior and keybindings may conflict.',
236	      8000,
237	    );
238	    this.data.coexistenceWarned = true;
239	    await this.saveData(this.data);
240	  }
241	}
