243	class TrueOutlinerSettingTab extends PluginSettingTab {
244	  constructor(
245	    app: App,
246	    private readonly plugin: TrueOutlinerPlugin,
247	  ) {
248	    super(app, plugin);
249	  }
250	
251	  override display(): void {
252	    this.containerEl.empty();
253	    new Setting(this.containerEl)
254	      .setName('Debug: cross-check parser against metadata cache')
255	      .setDesc(
256	        'Logs disagreements between the plugin parser and Obsidian metadata to the developer console when a structural command runs.',
257	      )
258	      .addToggle((toggle) =>
259	        toggle
260	          .setValue(this.plugin.debugCrossCheck)
261	          .onChange((value) => void this.plugin.setDebugCrossCheck(value)),
262	      );
263	    new Setting(this.containerEl)
264	      .setName('Debug: block marker visibility (experiment 5a)')
265	      .setDesc(
266	        'Which nodes get a block marker icon at all. Most leaf atom kinds (code, table, callout, quote, HTML, hr) already carry their own native visual style, so a marker may only be worth showing on branch nodes. Takes effect on the next edit or note switch.',
267	      )
268	      .addDropdown((dropdown) =>
269	        dropdown
270	          .addOptions(MARKER_VISIBILITY_LABELS)
271	          .setValue(this.plugin.markerVisibility)
272	          .onChange((value) => void this.plugin.setMarkerVisibility(value as MarkerVisibility)),
273	      );
274	  }
275	}
