214	/** getBoundingClientRect() of the Nth (0-indexed) `.cm-line` in the active editor. */
215	export function getLineRect(lineIndex: number): Promise<Rect> {
216	  return browser.executeObsidian(
217	    ({ app, obsidian }, lineIndex) => {
218	      const view = app.workspace.getActiveViewOfType(obsidian.MarkdownView);
